/**
 * Shared handle/promise/cancellation state machine for SDK-backed runners.
 * Guards `terminated` / `cancelInitiated`, attaches/detaches signal listeners,
 * and funnels cancel through a single `cancelInternal` with retry-on-transient.
 */

import type { AgentRunHandle, AgentRunResult } from "./runner.js";

export interface SdkRunHandleCallbacks {
  readonly finalizeOk: (terminal: AgentRunResult) => void;
  readonly finalizeError: (err: unknown) => void;
  readonly detachSignalListener: () => void;
}

export interface SdkRunHandleState {
  readonly result: Promise<AgentRunResult>;
  readonly cancelInternal: () => Promise<void>;
  readonly callbacks: SdkRunHandleCallbacks;
}

/** Builds the promise + cancel machinery shared by local and cloud SDK runners. */
export function createSdkRunHandleState(args: {
  readonly signal?: AbortSignal;
  readonly cancelRun: () => Promise<void>;
}): SdkRunHandleState {
  let terminated = false;
  let cancelInitiated = false;
  let resolveResult!: (value: AgentRunResult) => void;
  let rejectResult!: (reason: unknown) => void;
  const result = new Promise<AgentRunResult>((resolve, reject) => {
    resolveResult = resolve;
    rejectResult = reject;
  });

  let signalListener: (() => void) | undefined;
  const detachSignalListener = (): void => {
    if (signalListener !== undefined && args.signal !== undefined) {
      args.signal.removeEventListener("abort", signalListener);
    }
    signalListener = undefined;
  };

  const cancelInternal = async (): Promise<void> => {
    if (terminated || cancelInitiated) return;
    cancelInitiated = true;
    try {
      await args.cancelRun();
    } catch {
      cancelInitiated = false;
    }
  };

  if (args.signal !== undefined) {
    if (args.signal.aborted) {
      void cancelInternal();
    } else {
      signalListener = (): void => {
        void cancelInternal();
      };
      args.signal.addEventListener("abort", signalListener, { once: true });
    }
  }

  const callbacks: SdkRunHandleCallbacks = {
    detachSignalListener,
    finalizeError: (err) => {
      if (terminated) return;
      terminated = true;
      detachSignalListener();
      rejectResult(err);
    },
    finalizeOk: (terminal) => {
      if (terminated) return;
      terminated = true;
      detachSignalListener();
      resolveResult(terminal);
    },
  };

  return { callbacks, cancelInternal, result };
}

export function buildSdkRunHandle(args: {
  readonly agentId: string;
  readonly runId: string;
  readonly state: SdkRunHandleState;
}): AgentRunHandle {
  return {
    agentId: args.agentId,
    cancel: args.state.cancelInternal,
    result: args.state.result,
    runId: args.runId,
  };
}

/**
 * Typed error subclasses for `@ship/agent-runner`. Provider-specific
 * subclasses live in their runner packages and extend `AgentRunFailedError`.
 */

/** Thrown when a required API key env var is unset before any provider call. */
export class MissingApiKeyError extends Error {
  override readonly name = "MissingApiKeyError";

  constructor(message = "CURSOR_API_KEY environment variable is not set") {
    super(message);
  }
}

/**
 * Thrown when a provider cannot start or attach to a run. The original
 * error lives in `cause`. Post-run failures are NOT thrown — they surface
 * as `handle.result` resolving with `status: "failed"`.
 */
export class AgentRunFailedError extends Error {
  override readonly name: string = "AgentRunFailedError";
}

function renderPrimitiveCause(cause: unknown): string | undefined {
  if (cause instanceof Error && cause.message !== "") return cause.message;
  if (typeof cause === "string") return cause;
  if (typeof cause === "number" || typeof cause === "boolean" || typeof cause === "bigint") {
    return String(cause);
  }
  if (cause === null || cause === undefined) return "";
  return undefined;
}

function causeMessage(cause: unknown): string {
  const primitive = renderPrimitiveCause(cause);
  if (primitive !== undefined) return primitive;
  if (typeof cause === "function" || typeof cause === "symbol") return "[unstringifiable cause]";
  try {
    return JSON.stringify(cause);
  } catch {
    return "[unstringifiable cause]";
  }
}

/** Pre-run / stream failure with the underlying cause folded into `.message`. */
export function agentRunFailedError(message: string, cause: unknown): AgentRunFailedError {
  const detail = causeMessage(cause);
  const combined = detail !== "" && !message.includes(detail) ? `${message}: ${detail}` : message;
  return new AgentRunFailedError(combined, { cause });
}

/** Thrown when attach/resume targets a missing agent or artifact path. */
export class AgentNotFoundError extends AgentRunFailedError {
  override readonly name: string = "AgentNotFoundError";
  readonly agentId: string;
  readonly runId: string;

  constructor(args: { agentId: string; runId: string; message?: string; cause?: unknown }) {
    super(
      args.message ?? `Agent not found (agentId=${args.agentId}, runId=${args.runId})`,
      args.cause !== undefined ? { cause: args.cause } : undefined,
    );
    this.agentId = args.agentId;
    this.runId = args.runId;
  }
}

// Pure failure classification + bounded detail builder. Reads events through
// an injected `EventProjection` so provider spellings never reach policy.

import type { FailureCategory } from "@ship/workflow";

import { LOCAL_RUN_CONTENTION_HINT } from "@ship/workflow";

import type { AgentEvent, EventProjection } from "./event-projection.js";

import { formatRunningToolAge } from "./formatters.js";
import {
  lastFailedToolCallDetail,
  lastRunningToolCall,
  runningToolAgeMs,
  runningToolDetail,
} from "./projection-helpers.js";

const NEAR_CAP_DURATION_RATIO = 0.95;
const COLLAPSE_DURATION_RATIO = 0.8;
const RUNNING_TOOL_MIN_AGE_MS = 30_000;
const MAX_FAILURE_DETAIL_CHARS = 512;
const TRUNCATED_SUFFIX = "...";

function boundFailureDetail(text: string): string {
  if (text.length <= MAX_FAILURE_DETAIL_CHARS) return text;
  const keep = MAX_FAILURE_DETAIL_CHARS - TRUNCATED_SUFFIX.length;
  return `${text.slice(0, keep)}${TRUNCATED_SUFFIX}`;
}

export interface ClassifyFailureInput<E = AgentEvent> {
  readonly projection: EventProjection<E>;
  readonly sdkTerminalStatus?: string;
  readonly isStoreContention?: boolean;
  readonly thrownError?: boolean;
  readonly durationMs?: number;
  readonly maxRunDurationMs?: number;
  readonly events: readonly E[];
}

export interface BuildFailureDetailInput<E = AgentEvent> {
  readonly projection: EventProjection<E>;
  readonly category: FailureCategory;
  readonly sdkTerminalStatus?: string;
  readonly durationMs?: number;
  readonly maxRunDurationMs?: number;
  readonly events: readonly E[];
  readonly rawErrorMessage?: string;
  readonly thrownErr?: unknown;
}

function isNearCap(durationMs: number | undefined, maxRunDurationMs: number | undefined): boolean {
  if (durationMs === undefined || maxRunDurationMs === undefined) return false;
  return durationMs >= NEAR_CAP_DURATION_RATIO * maxRunDurationMs;
}

function isCollapseDuration(
  durationMs: number | undefined,
  maxRunDurationMs: number | undefined,
): boolean {
  if (durationMs === undefined || maxRunDurationMs === undefined) return false;
  return durationMs > COLLAPSE_DURATION_RATIO * maxRunDurationMs;
}

function normalizeSdkStatus(status: string | undefined): string | undefined {
  if (status === undefined || status.length === 0) return undefined;
  return status.toLowerCase();
}

function isExpiredStatus(status: string | undefined): boolean {
  return normalizeSdkStatus(status) === "expired";
}

function agentCollapseOnRunningTool<E>(input: ClassifyFailureInput<E>): boolean {
  const running = lastRunningToolCall(input.projection, input.events);
  if (running === undefined) return false;
  if (!isCollapseDuration(input.durationMs, input.maxRunDurationMs)) return false;
  const age = runningToolAgeMs(
    input.projection,
    running,
    input.events,
    input.durationMs,
    RUNNING_TOOL_MIN_AGE_MS,
  );
  if (age === undefined) return false;
  return age > RUNNING_TOOL_MIN_AGE_MS;
}

export function classifyFailure<E = AgentEvent>(input: ClassifyFailureInput<E>): FailureCategory {
  if (input.isStoreContention === true) return "contention";
  if (input.thrownError === true) return "sdk-throw";
  if (lastFailedToolCallDetail(input.projection, input.events) !== undefined) return "logic";
  if (agentCollapseOnRunningTool(input)) return "agent-collapse-on-running-tool";
  if (isExpiredStatus(input.sdkTerminalStatus)) return "timeout-near-cap";
  if (isNearCap(input.durationMs, input.maxRunDurationMs)) return "timeout-near-cap";
  return "unknown";
}

function thrownErrorMessage(err: unknown): string | undefined {
  if (err instanceof Error && err.message.length > 0) return err.message;
  if (typeof err === "string" && err.length > 0) return err;
  return undefined;
}

function detailForContention<E>(input: BuildFailureDetailInput<E>): string {
  const fromErr = thrownErrorMessage(input.thrownErr);
  if (fromErr?.includes(LOCAL_RUN_CONTENTION_HINT) === true) return fromErr;
  return LOCAL_RUN_CONTENTION_HINT;
}

function detailForSdkThrow<E>(input: BuildFailureDetailInput<E>): string {
  const fromErr = thrownErrorMessage(input.thrownErr);
  if (fromErr !== undefined) return fromErr;
  if (input.rawErrorMessage !== undefined && input.rawErrorMessage.length > 0) {
    return input.rawErrorMessage;
  }
  return "SDK error before terminal result";
}

function detailForLogic<E>(input: BuildFailureDetailInput<E>): string {
  const detail = lastFailedToolCallDetail(input.projection, input.events);
  if (detail !== undefined) return detail;
  if (input.rawErrorMessage !== undefined && input.rawErrorMessage.length > 0) {
    return input.rawErrorMessage;
  }
  return "tool_call failed";
}

function detailForAgentCollapse<E>(input: BuildFailureDetailInput<E>): string {
  const running = lastRunningToolCall(input.projection, input.events);
  if (running === undefined) return "agent stopped with a running tool_call";
  const age =
    runningToolAgeMs(
      input.projection,
      running,
      input.events,
      input.durationMs,
      RUNNING_TOOL_MIN_AGE_MS,
    ) ??
    input.durationMs ??
    0;
  return runningToolDetail(running, age, formatRunningToolAge);
}

function detailForTimeoutNearCap<E>(input: BuildFailureDetailInput<E>): string {
  const { durationMs, maxRunDurationMs } = input;
  const capPart =
    maxRunDurationMs !== undefined
      ? `duration ${formatRunningToolAge(durationMs ?? 0)} (cap ${formatRunningToolAge(maxRunDurationMs)})`
      : `duration ${formatRunningToolAge(durationMs ?? 0)}`;
  if (isExpiredStatus(input.sdkTerminalStatus)) {
    return `SDK status expired; ${capPart}`;
  }
  return capPart;
}

function detailForUnknown<E>(input: BuildFailureDetailInput<E>): string {
  if (input.rawErrorMessage !== undefined && input.rawErrorMessage.length > 0) {
    return input.rawErrorMessage;
  }
  const fromErr = thrownErrorMessage(input.thrownErr);
  if (fromErr !== undefined) return fromErr;
  if (input.sdkTerminalStatus !== undefined && input.sdkTerminalStatus.length > 0) {
    return `SDK status ${input.sdkTerminalStatus}`;
  }
  return "no classification signals";
}

const DETAIL_BUILDERS: Record<FailureCategory, <E>(input: BuildFailureDetailInput<E>) => string> = {
  contention: detailForContention,
  "timeout-near-cap": detailForTimeoutNearCap,
  "agent-collapse-on-running-tool": detailForAgentCollapse,
  "sdk-throw": detailForSdkThrow,
  logic: detailForLogic,
  unknown: detailForUnknown,
};

export function buildFailureDetail<E = AgentEvent>(input: BuildFailureDetailInput<E>): string {
  return boundFailureDetail(DETAIL_BUILDERS[input.category](input));
}

export function formatClassifiedErrorMessage(category: FailureCategory, detail: string): string {
  return `${category}; ${detail}`;
}

/**
 * `FakeAgentRunner` — scriptable stand-in for production runners.
 * Exported under `@ship/agent-runner/test/fake`. Downstream tests drive
 * it deterministically with no API key and no network.
 */

import type { ArtifactRef } from "@ship/workflow";

import type { AgentEvent } from "./event-projection.js";
import type {
  AgentRunAttachInput,
  AgentRunHandle,
  AgentRunInput,
  AgentRunner,
  AgentRunResult,
} from "./runner.js";

import { attachInputAsRunInput } from "./attach-input.js";
import { AgentNotFoundError } from "./errors.js";
import { MAX_CLASSIFICATION_EVENTS } from "./formatters.js";

/** A single scripted run. The fake pops one of these per `run()` call. */
export interface FakeAgentScript {
  readonly events: readonly AgentEvent[];
  readonly result: AgentRunResult;
  readonly listArtifacts?: () => Promise<readonly ArtifactRef[] | undefined>;
  readonly cancelBehavior?: "complete" | "ignore" | "throw";
  readonly delayMsBetweenEvents?: number;
  readonly artifactBytes?: Readonly<Record<string, Buffer>>;
}

export type FakeAgentAttachScript =
  | FakeAgentScript
  | {
      readonly notFound: true;
    };

function isFakeAttachNotFound(
  script: FakeAgentAttachScript,
): script is { readonly notFound: true } {
  return "notFound" in script;
}

export interface FakeAgentAttachCall {
  readonly input: AgentRunAttachInput;
  readonly script: FakeAgentAttachScript;
}

export interface FakeAgentRunCall {
  readonly input: AgentRunInput;
  readonly script: FakeAgentScript;
}

const CANCEL_THROWN_MESSAGE = "FakeAgentRunner: scripted cancel error";

export interface FakeAgentRunnerOptions {
  readonly defaultScript?: FakeAgentScript;
  readonly defaultAttachScript?: FakeAgentAttachScript;
}

export class FakeAgentRunner implements AgentRunner {
  readonly #scripts: FakeAgentScript[] = [];
  readonly #attachScripts: FakeAgentAttachScript[] = [];
  readonly #calls: FakeAgentRunCall[] = [];
  readonly #attachCalls: FakeAgentAttachCall[] = [];
  readonly #defaultScript: FakeAgentScript | undefined;
  readonly #defaultAttachScript: FakeAgentAttachScript | undefined;
  readonly #artifactBytesByAgent = new Map<string, Map<string, Buffer>>();
  #runCounter = 0;

  constructor(opts: FakeAgentRunnerOptions = {}) {
    this.#defaultScript = opts.defaultScript;
    this.#defaultAttachScript = opts.defaultAttachScript;
  }

  enqueue(script: FakeAgentScript): void {
    this.#scripts.push(script);
  }

  enqueueAttach(script: FakeAgentAttachScript): void {
    this.#attachScripts.push(script);
  }

  get calls(): readonly FakeAgentRunCall[] {
    return this.#calls;
  }

  get attachCalls(): readonly FakeAgentAttachCall[] {
    return this.#attachCalls;
  }

  get pendingScriptCount(): number {
    return this.#scripts.length;
  }

  run(input: AgentRunInput): Promise<AgentRunHandle> {
    const script = this.#scripts.shift() ?? this.#defaultScript;
    if (script === undefined) {
      return Promise.reject(
        new Error(
          "FakeAgentRunner: run() called with no script enqueued and no defaultScript provided",
        ),
      );
    }
    this.#calls.push({ input, script });

    this.#runCounter += 1;
    const callIndex = this.#runCounter;
    const agentId = `agent-fake-${callIndex.toString().padStart(4, "0")}`;
    if (script.artifactBytes !== undefined) {
      this.#artifactBytesByAgent.set(agentId, new Map(Object.entries(script.artifactBytes)));
    }
    return Promise.resolve(
      this.#buildScriptedHandle({
        agentId,
        input,
        runId: `run-fake-${callIndex.toString().padStart(4, "0")}`,
        script,
      }),
    );
  }

  downloadArtifact(agentId: string, path: string): Promise<Buffer> {
    const perAgent = this.#artifactBytesByAgent.get(agentId);
    const bytes = perAgent?.get(path);
    if (bytes === undefined) {
      throw new AgentNotFoundError({ agentId, runId: "" });
    }
    return Promise.resolve(bytes);
  }

  attach(input: AgentRunAttachInput): Promise<AgentRunHandle> {
    const script = this.#attachScripts.shift() ?? this.#defaultAttachScript;
    if (script === undefined) {
      return Promise.reject(
        new Error(
          "FakeAgentRunner: attach() called with no script enqueued and no defaultAttachScript provided",
        ),
      );
    }
    this.#attachCalls.push({ input, script });

    if (isFakeAttachNotFound(script)) {
      return Promise.reject(new AgentNotFoundError({ agentId: input.agentId, runId: input.runId }));
    }

    return Promise.resolve(
      this.#buildScriptedHandle({
        agentId: input.agentId,
        input: attachInputAsRunInput(input),
        runId: input.runId,
        script,
      }),
    );
  }

  #buildScriptedHandle(args: {
    agentId: string;
    input: AgentRunInput;
    runId: string;
    script: FakeAgentScript;
  }): AgentRunHandle {
    const { agentId, input, runId, script } = args;
    let terminated = false;
    let cancelAttempted = false;
    let resolveResult!: (value: AgentRunResult) => void;
    const result = new Promise<AgentRunResult>((resolve) => {
      resolveResult = resolve;
    });

    let activeSleep: { cancel: () => void } | null = null;
    let signalListener: (() => void) | null = null;

    const finalize = (terminal: AgentRunResult): void => {
      if (terminated) return;
      terminated = true;
      activeSleep?.cancel();
      activeSleep = null;
      if (signalListener !== null && input.signal !== undefined) {
        input.signal.removeEventListener("abort", signalListener);
      }
      signalListener = null;
      resolveResult(terminal);
    };

    const cancelInternal = (): Promise<void> => {
      const behavior = script.cancelBehavior ?? "complete";
      if (cancelAttempted) return Promise.resolve();
      cancelAttempted = true;
      if (behavior === "throw" && !terminated) {
        return Promise.reject(new Error(CANCEL_THROWN_MESSAGE));
      }
      if (behavior === "ignore") return Promise.resolve();
      finalize({ ...script.result, status: "cancelled" });
      return Promise.resolve();
    };

    const hardCancelFromSignal = (): void => {
      if (terminated) return;
      cancelAttempted = true;
      finalize({ ...script.result, status: "cancelled" });
    };

    if (input.signal !== undefined) {
      if (input.signal.aborted) {
        hardCancelFromSignal();
      } else {
        signalListener = hardCancelFromSignal;
        input.signal.addEventListener("abort", signalListener, { once: true });
      }
    }

    const setActiveSleep = (s: { cancel: () => void } | null): void => {
      activeSleep = s;
    };
    void this.#emit(script, input, () => terminated, finalize, setActiveSleep);

    return { agentId, cancel: cancelInternal, result, runId };
  }

  async #emit(
    script: FakeAgentScript,
    input: AgentRunInput,
    isTerminated: () => boolean,
    finalize: (terminal: AgentRunResult) => void,
    setActiveSleep: (s: { cancel: () => void } | null) => void,
  ): Promise<void> {
    const delay = script.delayMsBetweenEvents ?? 0;
    for (const ev of script.events) {
      if (delay > 0) {
        const s = abortableSleep(delay);
        setActiveSleep(s);
        await s.promise;
        setActiveSleep(null);
      }
      if (isTerminated()) return;
      try {
        const maybePromise: unknown = input.onEvent(ev);
        if (isPromiseLike(maybePromise)) {
          maybePromise.then(undefined, () => {
            /* swallow */
          });
        }
      } catch {
        /* swallow */
      }
    }
    if (!isTerminated()) {
      if (script.listArtifacts !== undefined) {
        const artifacts = await script.listArtifacts();
        const terminal = artifacts !== undefined ? { ...script.result, artifacts } : script.result;
        finalize(finalizeFakeResult(script, terminal));
        return;
      }
      finalize(finalizeFakeResult(script, script.result));
    }
  }
}

function finalizeFakeResult(script: FakeAgentScript, terminal: AgentRunResult): AgentRunResult {
  if (script.events.length === 0) return terminal;
  return { ...terminal, classificationEvents: script.events.slice(-MAX_CLASSIFICATION_EVENTS) };
}

function isPromiseLike(value: unknown): value is Promise<unknown> {
  return (
    value !== null &&
    typeof value === "object" &&
    typeof (value as { then?: unknown }).then === "function"
  );
}

function abortableSleep(ms: number): { promise: Promise<void>; cancel: () => void } {
  let cancelFn!: () => void;
  const promise = new Promise<void>((resolve) => {
    const t = setTimeout(resolve, ms);
    cancelFn = (): void => {
      clearTimeout(t);
      resolve();
    };
  });
  return { cancel: cancelFn, promise };
}

/** Duration and event-window formatters shared by classifiers and runners. */

export function formatWallDuration(ms: number): string {
  const totalMin = Math.max(0, Math.round(ms / 60_000));
  if (totalMin < 60) return `${String(totalMin)}m`;
  const hours = Math.floor(totalMin / 60);
  const rem = totalMin % 60;
  return rem > 0 ? `${String(hours)}h${String(rem)}m` : `${String(hours)}h`;
}

/** Second-granularity formatter for in-flight tool_call age in error/detail text. */
export function formatRunningToolAge(ms: number): string {
  const totalSec = Math.max(0, Math.round(ms / 1000));
  const min = Math.floor(totalSec / 60);
  const sec = totalSec % 60;
  if (min === 0) return `${String(sec)}s`;
  if (sec === 0) return `${String(min)}m`;
  return `${String(min)}m${String(sec)}s`;
}

/** Upper bound on streamed events retained for failure classification. */
export const MAX_CLASSIFICATION_EVENTS = 256;

const TOOL_COMMAND_SUMMARY_MAX = 80;

function truncateCommandSummary(command: string): string {
  if (command.length <= TOOL_COMMAND_SUMMARY_MAX) return command;
  const keep = TOOL_COMMAND_SUMMARY_MAX - 3;
  return `${command.slice(0, keep)}...`;
}

export function summarizeToolCall(name: string | undefined, command: string | undefined): string {
  const toolName = name ?? "tool";
  if (command === undefined) return toolName;
  return `${toolName} '${truncateCommandSummary(command)}'`;
}

export function stringifyToolCallResult(result: unknown): string {
  if (typeof result === "string") return result;
  if (typeof result === "number" || typeof result === "boolean" || typeof result === "bigint") {
    return String(result);
  }
  if (result === undefined || result === null) return "";
  if (typeof result === "function" || typeof result === "symbol") return "tool_call error";
  try {
    return JSON.stringify(result);
  } catch {
    return "tool_call error";
  }
}

