      thresholds: {
        statements: 90,
        branches: 85,
        functions: 90,
        lines: 90,
      },
    },
  },
});

/** Projection-driven helpers for event streams. */

import type { EventProjection } from "./event-projection.js";

import { summarizeToolCall } from "./formatters.js";

export function lastEventTimestamp<E>(
  projection: EventProjection<E>,
  events: readonly E[],
): number | undefined {
  for (let i = events.length - 1; i >= 0; i--) {
    const ev = events[i];
    if (ev === undefined) continue;
    const ts = projection.timestamp(ev);
    if (ts !== undefined) return ts;
  }
  return undefined;
}

function finalStatusByCallId<E>(
  projection: EventProjection<E>,
  events: readonly E[],
): Map<string, string> {
  const byId = new Map<string, string>();
  for (const ev of events) {
    if (projection.eventKind(ev) !== "tool_call") continue;
    const id = projection.toolCallId(ev);
    const status = projection.toolCallStatus(ev);
    if (id !== undefined && status !== undefined) byId.set(id, status);
  }
  return byId;
}

export interface RunningToolCallView {
  readonly name: string | undefined;
  readonly command: string | undefined;
  readonly timestamp: number | undefined;
}

/** Most recent tool_call still running at stream end. */
export function lastRunningToolCall<E>(
  projection: EventProjection<E>,
  events: readonly E[],
): RunningToolCallView | undefined {
  const finalStatus = finalStatusByCallId(projection, events);
  for (let i = events.length - 1; i >= 0; i--) {
    const ev = events[i];
    if (ev === undefined) continue;
    if (projection.eventKind(ev) !== "tool_call") continue;
    const id = projection.toolCallId(ev);
    const rawStatus = projection.toolCallStatus(ev);
    const effectiveStatus = id !== undefined ? finalStatus.get(id) : rawStatus;
    if (effectiveStatus === "running") {
      return {
        command: projection.commandArg(ev),
        name: projection.toolCallName(ev),
        timestamp: projection.timestamp(ev),
      };
    }
  }
  return undefined;
}

export function runningToolAgeMs<E>(
  projection: EventProjection<E>,
  toolCall: RunningToolCallView,
  events: readonly E[],
  durationMs: number | undefined,
  minAgeMs: number,
): number | undefined {
  const toolTs = toolCall.timestamp;
  const endTs = lastEventTimestamp(projection, events);
  if (toolTs !== undefined && endTs !== undefined) {
    const age = endTs - toolTs;
    return age >= 0 ? age : undefined;
  }
  if (durationMs !== undefined && durationMs >= minAgeMs) return durationMs;
  return undefined;
}

export function runningToolDetail(
  toolCall: RunningToolCallView,
  ageMs: number,
  formatAge: (ms: number) => string,
): string {
  const summary = summarizeToolCall(toolCall.name, toolCall.command);
  return `last activity: ${summary} running ${formatAge(ageMs)}, never completed`;
}

export function lastTerminalStatus<E>(
  projection: EventProjection<E>,
  events: readonly E[],
): string | undefined {
  for (let i = events.length - 1; i >= 0; i--) {
    const ev = events[i];
    if (ev === undefined) continue;
    const status = projection.terminalStatus(ev);
    if (status !== undefined) return status;
  }
  return undefined;
}

export function lastFailedToolCallDetail<E>(
  projection: EventProjection<E>,
  events: readonly E[],
): string | undefined {
  let detail: string | undefined;
  for (const ev of events) {
    if (projection.eventKind(ev) !== "tool_call") continue;
    const status = projection.toolCallStatus(ev);
    if (status !== "error" && status !== "failed") continue;
    const resultText = projection.resultText(ev);
    if (resultText !== undefined && resultText.length > 0) {
      detail = resultText;
      continue;
    }
    const name = projection.toolCallName(ev) ?? "tool";
    detail = `${name} errored`;
  }
  return detail;
}

/** Table-driven tests for `classifyFailure` and `buildFailureDetail`. */

import type { SDKMessage } from "@cursor/sdk";

import { LOCAL_RUN_CONTENTION_HINT } from "@ship/workflow";
import { describe, expect, test } from "vitest";

import {
  buildFailureDetail,
  classifyFailure,
  formatClassifiedErrorMessage,
} from "./classify-failure.js";

const CAP_MS = 30 * 60 * 1000;

describe("classifyFailure", () => {
  test("empty events with no signals → unknown", () => {
    expect(classifyFailure({ events: [] })).toBe("unknown");
  });

  test("isStoreContention → contention (beats thrownError)", () => {
    expect(classifyFailure({ events: [], isStoreContention: true, thrownError: true })).toBe(
      "contention",
    );
  });

  test("thrownError → sdk-throw", () => {
    expect(classifyFailure({ events: [], thrownError: true })).toBe("sdk-throw");
  });

  test("latest failed tool_call → logic (failed status + name fallback)", () => {
    const events = [
      { type: "tool_call", status: "failed", name: "grep" },
    ] as unknown as SDKMessage[];
    expect(classifyFailure({ events })).toBe("logic");
  });

  test("latest failed tool_call → logic (error with result text)", () => {
    const events = [
      { type: "tool_call", status: "error", result: "first failure" },
      { type: "status", status: "ERROR" },
      { type: "tool_call", status: "failed", result: "latest failure" },
    ] as unknown as SDKMessage[];
    expect(classifyFailure({ events })).toBe("logic");
  });

  test("running tool_call near cap with age > 30s → agent-collapse-on-running-tool", () => {
    const events = [
      {
        type: "tool_call",
        status: "running",
        name: "shell",
        ts: "2026-06-01T12:00:00.000Z",
      },
      { type: "status", status: "ERROR", ts: "2026-06-01T12:25:00.000Z" },
    ] as unknown as SDKMessage[];
    expect(
      classifyFailure({
        durationMs: 25 * 60 * 1000,
        events,
        maxRunDurationMs: CAP_MS,
      }),
    ).toBe("agent-collapse-on-running-tool");
  });

  test("running tool_call without timestamps falls back to durationMs for age", () => {
    const events = [
      { type: "tool_call", status: "running", name: "shell" },
    ] as unknown as SDKMessage[];
    expect(
      classifyFailure({
        durationMs: 25 * 60 * 1000,
        events,
        maxRunDurationMs: CAP_MS,
      }),
    ).toBe("agent-collapse-on-running-tool");
  });

  test("running tool_call later completed (same call_id) is not agent-collapse", () => {
    const events = [
      {
        type: "tool_call",
        status: "running",
        name: "shell",
        call_id: "c1",
        ts: "2026-06-01T12:00:00.000Z",
      },
      {
        type: "tool_call",
        status: "completed",
        name: "shell",
        call_id: "c1",
        ts: "2026-06-01T12:05:00.000Z",
      },
    ] as unknown as SDKMessage[];
    // The tool finished — no running tool_call remains, so a long run is not a
    // collapse. 0.85×cap is collapse-duration but below near-cap → unknown.
    expect(classifyFailure({ durationMs: 0.85 * CAP_MS, events, maxRunDurationMs: CAP_MS })).toBe(
      "unknown",
    );
  });

  test("a still-running call_id is agent-collapse even when another completed", () => {
    const events = [
      {
        type: "tool_call",
        status: "completed",
        name: "grep",
        call_id: "c1",
        ts: "2026-06-01T12:00:00.000Z",
      },
      {
        type: "tool_call",
        status: "running",
        name: "shell",
        call_id: "c2",
        ts: "2026-06-01T12:01:00.000Z",
      },
      { type: "status", status: "ERROR", ts: "2026-06-01T12:25:00.000Z" },
    ] as unknown as SDKMessage[];
    expect(classifyFailure({ durationMs: 25 * 60 * 1000, events, maxRunDurationMs: CAP_MS })).toBe(
      "agent-collapse-on-running-tool",
    );
  });

  test("sdkTerminalStatus expired (any case) → timeout-near-cap", () => {
    expect(classifyFailure({ events: [], sdkTerminalStatus: "EXPIRED" })).toBe("timeout-near-cap");
    expect(classifyFailure({ events: [], sdkTerminalStatus: "expired" })).toBe("timeout-near-cap");
  });

  test("durationMs ≥ 0.95×cap → timeout-near-cap", () => {
    expect(
      classifyFailure({
        durationMs: 0.96 * CAP_MS,
        events: [],
        maxRunDurationMs: CAP_MS,
      }),
    ).toBe("timeout-near-cap");
  });

  test("never returns undefined", () => {
    const category = classifyFailure({ events: [] });
    expect(category).toBeDefined();
    expect(typeof category).toBe("string");
  });
});

describe("buildFailureDetail", () => {
